import {
  returnOrThrow,
  getWrapper,
  postWrapper,
  putWrapper,
  deleteWrapper,
  ADMIN_CATEGORIES,
} from "./util";

export const adminCategoriesList = async () => {
  const resJSON = await getWrapper(ADMIN_CATEGORIES);
  return returnOrThrow(resJSON);
};

export const adminCategoryDetails = async (id) => {
  const resJSON = await getWrapper(`${ADMIN_CATEGORIES}/${id}`);
  return returnOrThrow(resJSON);
};

export const adminCreateCategory = async (data) => {
  const resJSON = await postWrapper(ADMIN_CATEGORIES, data);
  return returnOrThrow(resJSON);
};

export const adminUpdateCategory = async (id, data) => {
  const resJSON = await putWrapper(`${ADMIN_CATEGORIES}/${id}`, data);
  return returnOrThrow(resJSON);
};

export const adminDeleteCategory = async (id) => {
  const resJSON = await deleteWrapper(`${ADMIN_CATEGORIES}/${id}`);
  return returnOrThrow(resJSON);
};
